import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './Header.css';

const publicNav = [
  { label: '서비스 소개', href: '#features' },
  { label: '이용 방법', href: '#how-it-works' },
  { label: '체험하기', href: '#chat-demo' },
  { label: '다운로드', href: '#download' },
];

function Header() {
  const navigate = useNavigate();
  const location = useLocation();
  const { isLoggedIn, isAdmin, logout } = useAuth();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 12);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    document.body.style.overflow = menuOpen ? 'hidden' : '';
    return () => {
      document.body.style.overflow = '';
    };
  }, [menuOpen]);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const renderNav = () => {
    if (!isLoggedIn) {
      return publicNav.map((item) => (
        <a key={item.href} href={location.pathname === '/' ? item.href : `/${item.href}`} className="nav-link">
          {item.label}
        </a>
      ));
    }

    return (
      <>
        <Link to="/dashboard" className="nav-link">대시보드</Link>
        {isAdmin && <Link to="/admin" className="nav-link">관리자</Link>}
        <Link to="/mypage" className="nav-link">마이페이지</Link>
      </>
    );
  };

  return (
    <header className={`header ${scrolled ? 'scrolled' : ''}`}>
      <div className="container header-inner">
        <Link to="/" className="brand">
          <div className="brand-mark">
            <span className="brand-ring" />
            <span className="brand-dot" />
          </div>
          <div className="brand-copy">
            <strong>메이티</strong>
            <span>AI Emotion Companion</span>
          </div>
        </Link>

        <nav className="nav-desktop">
          {renderNav()}
        </nav>

        <div className="header-actions">
          {!isLoggedIn ? (
            <>
              <button className="btn ghost-btn" onClick={() => navigate('/login')}>
                로그인
              </button>
              <button className="btn btn-primary" onClick={() => navigate('/signup')}>
                무료 체험 시작
              </button>
            </>
          ) : (
            <>
              <div className="user-chip">
                <span className="status-dot" />
                {isAdmin ? '관리자 모드' : '로그인됨'}
              </div>
              <button className="btn logout-btn" onClick={handleLogout}>
                로그아웃
              </button>
            </>
          )}
        </div>

        <button
          className={`hamburger ${menuOpen ? 'active' : ''}`}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="메뉴 열기"
        >
          <span />
          <span />
          <span />
        </button>
      </div>

      <div className={`mobile-overlay ${menuOpen ? 'open' : ''}`} onClick={() => setMenuOpen(false)} />
      <aside className={`mobile-drawer ${menuOpen ? 'open' : ''}`}>
        <div className="mobile-drawer-inner">
          <div className="mobile-top">
            <div className="mobile-brand">메이티</div>
            <button onClick={() => setMenuOpen(false)} className="mobile-close">✕</button>
          </div>

          <div className="mobile-nav" onClick={() => setMenuOpen(false)}>
            {renderNav()}
          </div>

          <div className="mobile-cta">
            {!isLoggedIn ? (
              <>
                <button className="btn btn-secondary" onClick={() => navigate('/login')}>로그인</button>
                <button className="btn btn-primary" onClick={() => navigate('/signup')}>무료 체험 시작</button>
              </>
            ) : (
              <button className="btn logout-btn" onClick={handleLogout}>로그아웃</button>
            )}
          </div>
        </div>
      </aside>
    </header>
  );
}

export default Header;
